/**
 * pdfHideTemplates.ts — SMuFL glyph bitmap templates (generated)
 *
 * 自動生成: scripts/templateGen.ts (Bravura.otf → bitmap)
 * 手動編集禁止。再生成は `npx tsx scripts/templateGen.ts`。
 *
 * 各 glyph は SMuFL canonical 名で identify される。
 * 各 size は staffSpace pixel (5 線の line spacing) を意味する。
 * runtime では layout 検出した `staffBand.lineSpacing` から最近傍 size を選ぶ。
 *
 * 含まれる glyph 一覧:
 *  - noteheadBlack (U+E0A4): black notehead (filled, quarter/eighth/etc.)
 *  - noteheadHalf (U+E0A3): half notehead (hollow, half note)
 *  - noteheadWhole (U+E0A2): whole notehead (oval hollow)
 *  - noteheadXBlack (U+E0A9): X notehead (percussion, filled)
 *  - accidentalSharp (U+E262): sharp #
 *  - accidentalFlat (U+E260): flat b
 *  - accidentalNatural (U+E261): natural ♮
 *  - accidentalDoubleSharp (U+E263): double sharp x
 *  - accidentalDoubleFlat (U+E264): double flat bb
 *  - gClef (U+E050): G clef (treble)
 *  - fClef (U+E062): F clef (bass)
 *  - cClef (U+E05C): C clef (alto/tenor)
 *  - unpitchedPercussionClef1 (U+E069): percussion clef (2 vertical bars)
 *  - restWhole (U+E4E3): whole rest
 *  - restHalf (U+E4E4): half rest
 *  - restQuarter (U+E4E5): quarter rest
 *  - rest8th (U+E4E6): eighth rest
 *  - rest16th (U+E4E7): 16th rest
 *
 * Bravura font (c) Steinberg Media Technologies GmbH, SIL Open Font License 1.1
 * フォント本体: corpus/fonts/Bravura.otf, ライセンス: corpus/fonts/LICENSE.txt
 */

/**
 * 1 つの SMuFL glyph の特定 staffSpace size における raster bitmap。
 * `data` は row-major、0 = 背景、1 = 前景 (黒インク)。
 */
export interface TemplateBitmap {
  width: number;
  height: number;
  data: Uint8Array;
}

/** template の SMuFL canonical 名 */
export type TemplateName =
  | 'noteheadBlack'
  | 'noteheadHalf'
  | 'noteheadWhole'
  | 'noteheadXBlack'
  | 'accidentalSharp'
  | 'accidentalFlat'
  | 'accidentalNatural'
  | 'accidentalDoubleSharp'
  | 'accidentalDoubleFlat'
  | 'gClef'
  | 'fClef'
  | 'cClef'
  | 'unpitchedPercussionClef1'
  | 'restWhole'
  | 'restHalf'
  | 'restQuarter'
  | 'rest8th'
  | 'rest16th';

/** 生成済みの staffSpace pixel size (template lookup の離散セット) */
export const TEMPLATE_STAFF_SPACE_SIZES = [8, 10, 12, 14, 16] as const;

/**
 * compact "0"/"1" 文字列 → Uint8Array (内部 helper、module load 時に 1 回だけ実行)
 */
function bits(s: string): Uint8Array {
  const out = new Uint8Array(s.length);
  for (let i = 0; i < s.length; i++) out[i] = s.charCodeAt(i) === 49 ? 1 : 0;
  return out;
}

