/**
 * `lineSpacing` (= staffSpace pixel) に最も近い template を返す。
 * lineSpacing が discrete サイズ間にある場合は最近傍を選ぶ。
 * 該当 glyph が template 表に無い場合は undefined。
 */
export function getTemplate(
  name: TemplateName,
  lineSpacing: number,
): TemplateBitmap | undefined {
  const variants = TEMPLATES[name];
  if (!variants) return undefined;
  let best: number | undefined;
  let bestDist = Infinity;
  for (const sz of TEMPLATE_STAFF_SPACE_SIZES) {
    if (!variants[sz]) continue;
    const d = Math.abs(sz - lineSpacing);
    if (d < bestDist) {
      bestDist = d;
      best = sz;
    }
  }
  return best === undefined ? undefined : variants[best];
}
